package main

import (
	"encoding/json"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the API response
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// In-memory storage for webhook configuration
var (
	webhookStorage = make(map[string]string)
	storageMutex   sync.RWMutex
)

// ConfigureWebhook handles the POST request to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate that webhook_url is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a test GET request with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is acceptable (2xx or 3xx)
	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Webhook URL validation failed with status code: " + resp.Status,
		})
	}

	// Save the webhook configuration
	storageMutex.Lock()
	webhookStorage["webhook_url"] = config.WebhookURL
	storageMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

// GetWebhookConfig returns the current webhook configuration
func GetWebhookConfig(ctx *fiber.Ctx) error {
	storageMutex.RLock()
	webhookURL, exists := webhookStorage["webhook_url"]
	storageMutex.RUnlock()

	if !exists {
		return ctx.Status(fiber.StatusNotFound).JSON(Response{
			Success: false,
			Message: "No webhook configured",
		})
	}

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"webhook_url": webhookURL,
	})
}

func main() {
	// Create a new Fiber app
	app := fiber.New(fiber.Config{
		JSONEncoder: json.Marshal,
		JSONDecoder: json.Unmarshal,
	})

	// Register routes
	app.Post("/configure-webhook", ConfigureWebhook)
	app.Get("/webhook-config", GetWebhookConfig)

	// Health check endpoint
	app.Get("/health", func(c *fiber.Ctx) error {
		return c.JSON(fiber.Map{
			"status": "ok",
		})
	})

	// Start the server
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatal(err)
	}
}

