// resolveAndValidateHost resolves hostname to IP and validates it
func resolveAndValidateHost(hostname string) (string, error) {
	// Resolve hostname to IP
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return "", fmt.Errorf("unable to resolve hostname")
	}

	if len(ips) == 0 {
		return "", fmt.Errorf("no IP addresses found")
	}

	// Use the first resolved IP and validate it
	ip := ips[0]
	if err := validateIPAddress(ip.String()); err != nil {
		return "", err
	}

	return ip.String(), nil
}

// validateHostname checks if the hostname is safe to connect to
func validateHostname(hostname string) error {
	// Convert to lowercase for comparison
	hostname = strings.ToLower(strings.TrimSpace(hostname))

	// Block localhost and loopback addresses
	blockedHosts := []string{
		"localhost",
		"127.0.0.1",
		"0.0.0.0",
		"::1",
		"[::1]",
	}

	for _, blocked := range blockedHosts {
		if hostname == blocked {
			return fmt.Errorf("localhost addresses are not allowed")
		}
	}

	// Block local/private network ranges
	if strings.HasPrefix(hostname, "192.168.") ||
		strings.HasPrefix(hostname, "10.") ||
		strings.HasPrefix(hostname, "172.16.") ||
		strings.HasPrefix(hostname, "172.17.") ||
		strings.HasPrefix(hostname, "172.18.") ||
		strings.HasPrefix(hostname, "172.19.") ||
		strings.HasPrefix(hostname, "172.20.") ||
		strings.HasPrefix(hostname, "172.21.") ||
		strings.HasPrefix(hostname, "172.22.") ||
		strings.HasPrefix(hostname, "172.23.") ||
		strings.HasPrefix(hostname, "172.24.") ||
		strings.HasPrefix(hostname, "172.25.") ||
		strings.HasPrefix(hostname, "172.26.") ||
		strings.HasPrefix(hostname, "172.27.") ||
		strings.HasPrefix(hostname, "172.28.") ||
		strings.HasPrefix(hostname, "172.29.") ||
		strings.HasPrefix(hostname, "172.30.") ||
		strings.HasPrefix(hostname, "172.31.") {
		return fmt.Errorf("private network addresses are not allowed")
	}

	// Block link-local addresses
	if strings.HasPrefix(hostname, "169.254.") {
		return fmt.Errorf("link-local addresses are not allowed")
	}

	// Block cloud metadata endpoints
	metadataEndpoints := []string{
		"169.254.169.254", // AWS, Azure, GCP metadata
		"metadata.google.internal",
		"metadata.azure.com",
	}

	for _, blocked := range metadataEndpoints {
		if hostname == blocked {
			return fmt.Errorf("metadata endpoints are not allowed")
		}
	}

	// Resolve hostname to IP and validate
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If DNS resolution fails, block the request
		return fmt.Errorf("unable to resolve hostname")
	}

	// Check each resolved IP
	for _, ip := range ips {
		if err := validateIPAddress(ip.String()); err != nil {
			return err
		}
	}

	return nil
}

// validateIPAddress checks if an IP address is safe
func validateIPAddress(ipStr string) error {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return fmt.Errorf("invalid IP address")
	}

	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return fmt.Errorf("resolved IP is not allowed")
	}

	// Additional check for IPv4 private ranges
	if ip.To4() != nil {
		if strings.HasPrefix(ipStr, "192.168.") ||
			strings.HasPrefix(ipStr, "10.") ||
			strings.HasPrefix(ipStr, "172.") ||
			strings.HasPrefix(ipStr, "169.254.") ||
			ipStr == "127.0.0.1" ||
			ipStr == "0.0.0.0" {
			return fmt.Errorf("private IP addresses are not allowed")
		}
	}

	return nil
}

