package main

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the JSON response structure
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// Global variable to store the configured webhook URL
var configuredWebhookURL string

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON format: " + err.Error(),
		})
	}

	// Validate that webhook_url is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Validate the webhook URL by sending a test GET request with 3 seconds timeout
	if err := validateWebhookURL(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Webhook validation failed: " + err.Error(),
		})
	}

	// Save the configuration
	configuredWebhookURL = config.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

// validateWebhookURL sends a test GET request to the webhook URL with a 3-second timeout
func validateWebhookURL(url string) error {
	// Create a context with 3 seconds timeout
	ctxWithTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create the GET request
	req, err := http.NewRequestWithContext(ctxWithTimeout, http.MethodGet, url, nil)
	if err != nil {
		return err
	}

	// Send the request
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	// Check if the response status code is in the 2xx range
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fiber.NewError(fiber.StatusBadRequest, "webhook returned non-2xx status code")
	}

	return nil
}

// GetWebhook returns the currently configured webhook URL
func GetWebhook(ctx *fiber.Ctx) error {
	return ctx.JSON(fiber.Map{
		"webhook_url": configuredWebhookURL,
	})
}

func main() {
	// Create a new Fiber app
	app := fiber.New(fiber.Config{
		JSONEncoder: json.Marshal,
		JSONDecoder: json.Unmarshal,
	})

	// Register routes
	app.Post("/configure-webhook", ConfigureWebhook)
	app.Get("/webhook", GetWebhook)

	// Start the server
	log.Println("Server starting on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatal(err)
	}
}

