	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isIPAddress checks if a string is an IP address (including decimal notation)
func isIPAddress(hostname string) bool {
	// Check standard IP format
	if net.ParseIP(hostname) != nil {
		return true
	}

	// Check decimal IP format
	if parseDecimalIP(hostname) != nil {
		return true
	}

	return false
}

// parseDecimalIP attempts to parse a decimal IP address
func parseDecimalIP(hostname string) net.IP {
	// Try to parse as decimal notation (e.g., 2130706433 for 127.0.0.1)
	var num uint64
	_, err := fmt.Sscanf(hostname, "%d", &num)
	if err != nil {
		return nil
	}

	// Convert to IP address
	if num > 0xFFFFFFFF {
		return nil
	}

	ip := make(net.IP, 4)
	ip[0] = byte(num >> 24)
	ip[1] = byte(num >> 16)
	ip[2] = byte(num >> 8)
	ip[3] = byte(num)

	return ip
}

// isPrivateOrInternalIP checks if an IP address is private, loopback, link-local, or multicast
func isPrivateOrInternalIP(ip net.IP) bool {
	// Check for loopback
	if ip.IsLoopback() {
		return true
	}

	// Check for link-local
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for multicast
	if ip.IsMulticast() {
		return true
	}

	// Check for IPv4-mapped IPv6 addresses first
	if ip.To4() != nil {
		ip = ip.To4()
	}

	// Check for private IP ranges
	privateIPBlocks := []string{
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local
		"127.0.0.0/8",    // Loopback
		"fc00::/7",       // IPv6 unique local addr
		"fe80::/10",      // IPv6 link-local
		"::1/128",        // IPv6 loopback
	}

	for _, block := range privateIPBlocks {
		_, subnet, err := net.ParseCIDR(block)
		if err != nil {
			continue
		}
		if subnet.Contains(ip) {
			return true
		}
	}

	return false
}

// isDangerousHostname checks for dangerous hostnames
func isDangerousHostname(hostname string) bool {
	hostname = strings.ToLower(strings.TrimSpace(hostname))

	dangerousHosts := []string{
		"localhost",
		"127.0.0.1",
		"0.0.0.0",
		"::1",
		"metadata.google.internal", // Cloud metadata services
		"169.254.169.254",           // AWS/Azure metadata
	}

	for _, dangerous := range dangerousHosts {
		if hostname == dangerous || strings.HasSuffix(hostname, "."+dangerous) {
			return true
		}
	}

	return false
}

